import React from 'react';
import './About.css'; // Import your CSS file

function About() {
  return (
    <div className="about-container">
      <h1>About Me</h1>
      <p>
        Hi, I'm Shreya Banwaskar, a passionate front-end web developer who
        specializes in creating visually appealing and functional websites.
        I enjoy solving problems through code and building dynamic, responsive
        user interfaces.
      </p>
      <p>
        I have experience working with modern web technologies like React, JavaScript,
        and CSS to build highly interactive web applications.
      </p>
    </div>
  );
}

export default About;
